type TreeNode struct {
    Val   int
    Left  *TreeNode
    Right *TreeNode
}

func validateBinarySearchTree(root *TreeNode) bool {
    return isValidBST(root, nil, nil)
}

func isValidBST(node *TreeNode, min *int, max *int) bool {
    if node == nil {
        return true
    }
    if (min != nil && node.Val <= *min) || (max != nil && node.Val >= *max) {
        return false
    }
    return isValidBST(node.Left, min, &node.Val) && isValidBST(node.Right, &node.Val, max)
}

