}

public class Solution {
    public bool validateBinarySearchTree(TreeNode data) {
        return IsValidBST(data, null, null);
    }

    private bool IsValidBST(TreeNode node, int? min, int? max) {
        if (node == null) {
            return true;
        }
        if ((min.HasValue && node.val <= min.Value) || (max.HasValue && node.val >= max.Value)) {
            return false;
        }
        return IsValidBST(node.left, min, node.val) && IsValidBST(node.right, node.val, max);
    }
}

